"use client"
const formatter = new DateFormatter("en-US", {
  hour: "numeric",
  minute: "numeric",
  hour12: true,
})

export const DateInputTimeOnly = () => {
  return (
    <DateInput.Root granularity="minute" formatter={formatter} maxWidth="10rem">
      <DateInput.Label>Appointment time</DateInput.Label>
      <DateInput.Control>
        <DateInput.Segments />
      </DateInput.Control>
      <DateInput.HiddenInput />
    </DateInput.Root>
  )
}

"use client"
const ClearTrigger = () => {
  const dateInput = useDateInputContext()

  if (!dateInput.value.length) return null

  return (
    <IconButton
      aria-label="Clear date"
      variant="ghost"
      size="xs"
      marginStart="auto"
      onClick={() => dateInput.clearValue()}
    >
      <LuX />
    </IconButton>
  )
}

export const DateInputWithClearTrigger = () => {
  return (
    <DateInput.Root maxWidth="14rem">
      <DateInput.Label>Date of birth</DateInput.Label>
      <DateInput.Control>
        <DateInput.Segments />
        <ClearTrigger />
      </DateInput.Control>
      <DateInput.HiddenInput />
    </DateInput.Root>
  )
}

"use client"
const formSchema = z.object({
  dob: z.array(z.any()).min(1, { message: "Date of birth is required" }),
})

type FormValues = z.infer<typeof formSchema>

export const DateInputWithHookForm = () => {
  const { handleSubmit, control, formState } = useForm<FormValues>({
    resolver: standardSchemaResolver(formSchema),
    defaultValues: { dob: [] },
  })

  const onSubmit = handleSubmit((data) => console.log(data))

  return (
    <form onSubmit={onSubmit}>
      <Stack gap="4" align="flex-start" maxW="14rem">
        <Field.Root invalid={!!formState.errors.dob}>
          <Controller
            control={control}
            name="dob"
            render={({ field }) => (
              <DateInput.Root
                value={field.value}
                onValueChange={(e) => field.onChange(e.value)}
                invalid={!!formState.errors.dob}
              >
                <DateInput.Label>Date of birth</DateInput.Label>
                <DateInput.Control>
                  <DateInput.Segments />
                </DateInput.Control>
                <DateInput.HiddenInput />
              </DateInput.Root>
            )}
          />
          <Field.ErrorText>{formState.errors.dob?.message}</Field.ErrorText>
        </Field.Root>
        <Button type="submit">Submit</Button>
      </Stack>
    </form>
  )
}

